import React, {useState} from 'react';
import CBitsModal from "./CBitsModal";

const CBitsImage = (props) => {
    const [modalShow, setModalShow] = useState(false);
    const {image}= props;
    return (
            <div className="image-item" style={{paddingBottom: "35px"}} key={"image-"+image.number}>
                <img src={image.link} alt={image.tags.name} onClick={() => setModalShow(true)} />
                <p style={{
                    fontSize: "25px",
                    marginRight: "16px",
                    marginTop: "10px"
                }}>#{image.number}</p>

                <CBitsModal
                    image={image}
                    show={modalShow}
                    onHide={() => setModalShow(false)}
                />
            </div>
    );
};

export default CBitsImage;
