import React, {useEffect, useState} from "react"
import PropTypes from "prop-types"
import InfiniteScroll from "react-infinite-scroll-component"
import axios from "axios";
import {Card} from "react-bootstrap";
import CBitsImage from "./CBitsImage";


const ImageGallery = ({images, loading, fetchImages, hasMore}) => {
    return (
        <InfiniteScroll
            dataLength={images.length}
            next={() => fetchImages()}
            hasMore={hasMore}
            loader={
                <p style={{textAlign: "center", marginTop: "1%", paddingTop: "25px"}}/>
            }
        >
            <Card className="image-grid">
                {!loading
                    ? images.map(galleryImage => (
                        <CBitsImage image={galleryImage}/>
                    ))
                    : ""}
            </Card>
        </InfiniteScroll>
    );
}

const ImageProvider = (props) => {
    // Hold state
    const {searchResult, multiSelections, hasMore} = props;
    const [images, setImages] = useState([])
    const [loading, setLoading] = useState(true)
    const [counter, setCounter] = useState(0)

    // Fetch images on component mount
    useEffect(() => {
        if (multiSelections && multiSelections.length === 0) {
            setImages([])
            setLoading(false)
            setCounter(0)
            fetchImages()
        } else if (searchResult && searchResult.length !== 0) {
            setImages(searchResult)
            setLoading(false)
            setCounter(0)
        } else if (searchResult.length === 0) {
            setImages([])
            setLoading(false)
            setCounter(0)
        }
    }, [multiSelections, searchResult])


    // API endpoint
    const endpoint = "https://backend.cardanobits.art:9364"
    // Fetch Images from functions
    const fetchImages = () => {
        if (((multiSelections && multiSelections.length !== 0))) {
            const arratOfTags = multiSelections.map(a => a.label);
            axios(endpoint + `/tags/cardanobits?tags=${arratOfTags}&pageNumber=${counter + 1}`).then(res => {
                setImages([...images, ...res.data])
                setLoading(false)
                setCounter(counter + 1)
            })
        } else {
            axios(endpoint + "/cardanobits?number=" + counter).then(res => {
                setImages([...images, ...res.data.content])
                setLoading(false)
                setCounter(counter + 1)
            });
        }
    }

    return (
        <>
            <ImageGallery images={images} loading={loading} fetchImages={fetchImages} hasMore={hasMore}/>
        </>
    )
}


ImageGallery.propTypes =
    {
        images: PropTypes.array,
        loading: PropTypes.bool,
        fetchImages: PropTypes.func,
    }

export default ImageProvider